INSERT INTO `sys_config` VALUES (4, '交流加群', 'mp.msg', '交流QQ群：60235114（交流群是为了聚集开发者交流，加群请star项目，否则不通过，谢谢-开发者不可能没有gitee账号吧）', 'Y', 'admin', '2023-08-07 19:31:38', '', NULL, '是否开启验证码功能（true开启，false关闭）');
